ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name ?year WHERE {
  ?hf a :Healthcare_Facilities .
  ?hc a :Founding_Year .
  ?hf p:hasFounding_Year ?hc .
  ?hf p:name ?name .
  ?hc p:year ?year .
} }
  full: { SELECT ?name ?year ?owner_name ?acquisition_year WHERE {
  ?hf a :Healthcare_Facilities .
  ?hc a :Founding_Year .
  ?hf p:hasFounding_Year ?hc .
  ?po a :Past_Owners .
  ?hf p:hasPast_Owners ?po .
  ?hf p:name ?name .
  ?hc p:year ?year .
  ?po p:owner_name ?owner_name .
  ?po p:acquisition_year ?acquisition_year .
} }
  component_2: { SELECT ?name ?owner_name ?acquisition_year WHERE {
  ?hf a :Healthcare_Facilities .
  ?hc a :Past_Owners .
  ?hf p:hasPast_Owners ?hc .
  ?hf p:name ?name .
  ?hc p:owner_name ?owner_name .
  ?hc p:acquisition_year ?acquisition_year .
} }
}
